package controller; import javax.swing.*; import javax.swing.table.*; import util.JapandiTheme; import service.impl.*; import model.LostReport;
public class AdminLostReportFrame extends BaseFrame{ public AdminLostReportFrame(){super("後台 - 走失通報管理",760,560);JPanel p=root();p.add(header("走失通報管理"));DefaultTableModel m=new DefaultTableModel(new String[]{"姓名","位置","時間","警局","電話","狀態"},0);for(LostReport r:new EmergencyServiceImpl().lostReports())m.addRow(new Object[]{r.getName(),r.getLocation(),r.getTime(),r.getPoliceStation(),r.getPhone(),r.getStatus()});JTable t=new JTable(m);JScrollPane sp=new JScrollPane(t);sp.setBounds(38,105,680,360);p.add(sp);} }